func applyReviewTriageDecision(store ExecuteBeadLoopStore, beadID, actor string, now time.Time, currentPowerClass string) error {
	events, err := store.Events(beadID)
	if err != nil {
		return err
	}

	var blockTimestamps []time.Time
	var pairingDegraded []time.Time
	for _, ev := range events {
		switch {
		case ev.Kind == "review" && strings.TrimSpace(ev.Summary) == "BLOCK":
			blockTimestamps = append(blockTimestamps, ev.CreatedAt)
		case ev.Kind == ReviewPairingDegradedEventKind:
			pairingDegraded = append(pairingDegraded, ev.CreatedAt)
		}
	}

	// History excludes the current attempt. The just-appended BLOCK (if any)
	// is the last entry in blockTimestamps and must not be counted as prior
	// history per triage.Decide()'s contract.
	historyCount := len(blockTimestamps)
	if historyCount > 0 {
		historyCount--
	}
	history := make([]triage.FailureMode, 0, historyCount)
	for i := 0; i < historyCount; i++ {
		history = append(history, triage.FailureModeReviewBlock)
	}

	policy := triage.DefaultPolicy()
	action := policy.Decide(beadID, triage.FailureModeReviewBlock, history)

	pairedDegraded := latestBlockPairedDegraded(blockTimestamps, pairingDegraded)
	if pairedDegraded && action == triage.ActionEscalatePower {
		action = triage.ActionReAttemptWithContext
	}

	return applyTriageAction(store, beadID, actor, now, action, currentPowerClass, pairedDegraded)
}

// latestBlockPairedDegraded reports whether the most recent BLOCK event was
// paired with a review-pairing-degraded event from the same attempt window
// (between the previous BLOCK and this one).
func latestBlockPairedDegraded(blocks, pairing []time.Time) bool {
	if len(blocks) == 0 || len(pairing) == 0 {
		return false
	}
	latest := blocks[len(blocks)-1]
	var prev time.Time
	if len(blocks) >= 2 {
		prev = blocks[len(blocks)-2]
	}
	for _, t := range pairing {
		if t.After(prev) && !t.After(latest) {
			return true
		}
	}
	return false
}

// applyTriageAction performs the side effects for a chosen Action. Review-block
// escalation is attempt-scoped evidence only, recorded on the triage-decision
// event body. Operator-required outcomes may park the bead to proposed while
// clearing stale legacy retry-hint metadata, and every path records a
// triage-decision event.
func applyTriageAction(store ExecuteBeadLoopStore, beadID, actor string, now time.Time, action triage.Action, currentPowerClass string, pairedDegraded bool) error {
	body := map[string]any{
		"action": string(action),
		"mode":   string(triage.FailureModeReviewBlock),
	}
	if pairedDegraded {
		body["pairing_degraded"] = true
	}

	switch action {
	case triage.ActionEscalatePower:
		nextPowerClass := nextEscalatedPowerClass(currentPowerClass)
		body["next_power_class"] = string(nextPowerClass)
	case triage.ActionOperatorRequired:
		if err := parkToProposedWithOperatorMeta(store, beadID, bead.ParkPostReviewMalfunction, ParkToProposedOpts{
			Reason:          "review BLOCK triage reached operator-required rung",
			Summary:         "review BLOCK triage requires operator decision",
			SuggestedAction: "review the blocked attempt and accept, split, block, or cancel",
			Since:           now,
			CleanupLabels:   true,
			AdditionalMutate: func(b *bead.Bead) {
				if b.Extra == nil {
					b.Extra = make(map[string]any)
				}
			},
		}); err != nil {
			return err
		}
	}

	bodyJSON, _ := json.Marshal(body)
	return store.AppendEvent(beadID, bead.BeadEvent{
		Kind:      triageDecisionEventKind,
		Summary:   string(triage.FailureModeReviewBlock) + ": " + string(action),
		Body:      string(bodyJSON),
		Actor:     actor,
		Source:    "ddx work",
		CreatedAt: now,
	})
}

func clearReviewTriageClaimMetadata(b *bead.Bead) {
	b.Owner = ""
	if b.Extra == nil {
		return
	}
	for _, key := range bead.ClaimMetadataExtraKeys {
		delete(b.Extra, key)
	}
	delete(b.Extra, bead.ClaimHeartbeatExtraKey)
}

// nextEscalatedPowerClass returns the next powerClass above `current`. An unrecognised or
// empty current powerClass defaults to standard; smart is its own ceiling.
func nextEscalatedPowerClass(current string) escalation.PowerClass {
	switch escalation.PowerClass(current) {
	case escalation.PowerCheap:
		return escalation.PowerStandard
	case escalation.PowerStandard:
		return escalation.PowerSmart
	case escalation.PowerSmart:
		return escalation.PowerSmart
	default:
		return escalation.PowerStandard
	}
}

func adjudicateNoChangesContract(ctx context.Context, beadID string, report Report, projectRoot string, noChangesCount int, checker SatisfactionChecker, runner VerificationCommandRunner) (NoChangesOutcome, Report, error) {
	if checker != nil {
		satisfied, evidence, err := checker.CheckSatisfied(ctx, beadID, noChangesCount)
		if err != nil {
			return NoChangesOutcome{}, report, err
		}
		if satisfied {
			if evidence != "" {
				report.Detail = evidence
			}
			report.Status = StatusAlreadySatisfied
			return NoChangesOutcome{
				Satisfied:        true,
				Action:           NoChangesActionCloseAlreadySatisfied,
				CooldownEligible: false,
				Evidence:         evidence,
			}, report, nil
		}
		return NoChangesOutcome{
			Satisfied:        false,
			Action:           NoChangesActionBadAttemptNoCooldown,
			CooldownEligible: false,
		}, report, nil
	}

	parsed := ParseNoChangesRationale(report.NoChangesRationale)
	switch parsed.Kind {
	case NoChangesKindVerified:
		if runner == nil {
			runner = DefaultVerificationCommandRunner
		}
		exitCode, output, runErr := runner(ctx, projectRoot, parsed.VerificationCommand)
		body := fmt.Sprintf("verification_command=%s\nexit_code=%d", parsed.VerificationCommand, exitCode)
		if output != "" {
			body += "\noutput:\n" + output
		}
		if runErr != nil {
			body += "\nrun_error: " + runErr.Error()
		}
		if runErr == nil && exitCode == 0 {
			evidence := fmt.Sprintf("verification_command passed: %s", parsed.VerificationCommand)
			report.Detail = evidence
			report.Status = StatusAlreadySatisfied
			return NoChangesOutcome{
				Satisfied:        true,
				Action:           NoChangesActionCloseAlreadySatisfied,
				CooldownEligible: false,
				Evidence:         evidence,
				EventKind:        NoChangesEventVerified,
				EventBody:        body,
			}, report, nil
		}
		return NoChangesOutcome{
			Satisfied:        false,
			Action:           NoChangesActionBadAttemptNoCooldown,
			CooldownEligible: false,
			EventKind:        NoChangesEventUnverified,
			EventBody:        body,
			Label:            NoChangesLabelUnverified,
		}, report, nil
	case NoChangesKindLifecycleStatus:
		return adjudicateNoChangesLifecycleStatus(parsed, report), report, nil
	case NoChangesKindRejectedLegacyStatus:
		body := parsed.RejectionReason
		if parsed.Reason != "" {
			body += "\nreason: " + parsed.Reason
		}
		return NoChangesOutcome{
			Satisfied:        false,
			Action:           NoChangesActionBadAttemptNoCooldown,
			CooldownEligible: false,
			EventKind:        NoChangesEventLegacyStatusRejected,
			EventBody:        body,
			Reason:           body,
		}, report, nil
	default:
		body := strings.TrimSpace(report.NoChangesRationale)
		if body == "" {
			body = "(rationale absent)"
		}
		return NoChangesOutcome{
			Satisfied:        false,
			Action:           NoChangesActionBadAttemptNoCooldown,
			CooldownEligible: false,
			EventKind:        NoChangesEventUnjustified,
			EventBody:        body,
			Label:            NoChangesLabelUnjustified,
		}, report, nil
	}
}

func adjudicateNoChangesLifecycleStatus(parsed ParsedNoChangesRationale, report Report) NoChangesOutcome {
	reason := strings.TrimSpace(parsed.Reason)
	suggestedAction := strings.TrimSpace(parsed.SuggestedAction)
	switch parsed.LifecycleStatus {
	case "open":
		if reason == "" {
			reason = "autonomous work remains possible"
		}
		if suggestedAction == "" {
			suggestedAction = "retry with a smart agent"
		}
		return NoChangesOutcome{
			Satisfied:        false,
			Action:           NoChangesActionKeepOpenSmartRetry,
			CooldownEligible: false,
			EventKind:        NoChangesEventAutonomousRetry,
			EventBody:        noChangesLifecycleEventBody(parsed.LifecycleStatus, reason, suggestedAction),
			LifecycleStatus:  parsed.LifecycleStatus,
			Reason:           reason,
			SuggestedAction:  suggestedAction,
		}
	case "proposed":
		if reason == "" {
			reason = "operator decision required before another automated attempt"
		}
		if suggestedAction == "" {
			suggestedAction = "review and accept, split, block, or cancel this proposed work"
		}
		return NoChangesOutcome{
			Satisfied:        false,
			Action:           NoChangesActionOperatorRequired,
			CooldownEligible: false,
			EventKind:        NoChangesEventOperatorRequired,
			EventBody:        noChangesLifecycleEventBody(parsed.LifecycleStatus, reason, suggestedAction),
			LifecycleStatus:  parsed.LifecycleStatus,
			Reason:           reason,
			SuggestedAction:  suggestedAction,
		}
	case "blocked":
		if reason == "" {
			return noChangesUnsupportedStatusOutcome(parsed.LifecycleStatus, "status: blocked requires reason: <external recheckable blocker>")
		}
		if noChangesBlockedReasonIsInternal(reason, suggestedAction, report.NoChangesRationale) {
			if suggestedAction == "" {
				suggestedAction = "decompose into executable follow-up work or retry with a stronger agent"
			}
			return NoChangesOutcome{
				Satisfied:        false,
				Action:           NoChangesActionKeepOpenSmartRetry,
				CooldownEligible: false,
				EventKind:        NoChangesEventAutonomousRetry,
				EventBody:        noChangesLifecycleEventBody("open", reason, suggestedAction),
				LifecycleStatus:  "open",
				Reason:           reason,
				SuggestedAction:  suggestedAction,
			}
		}
		if suggestedAction == "" {
			suggestedAction = "recheck the external blocker and move status to open when cleared"
		}
		return NoChangesOutcome{
			Satisfied:        false,
			Action:           NoChangesActionBlockedExternal,
			CooldownEligible: false,
			EventKind:        NoChangesEventBlocked,
			EventBody:        noChangesLifecycleEventBody(parsed.LifecycleStatus, reason, suggestedAction),
			LifecycleStatus:  parsed.LifecycleStatus,
			Reason:           reason,
			SuggestedAction:  suggestedAction,
		}
	case "closed":
		return noChangesUnsupportedStatusOutcome(parsed.LifecycleStatus, "use verification_command to close an already-satisfied bead")
	case "cancelled":
		return noChangesUnsupportedStatusOutcome(parsed.LifecycleStatus, "cancelling work is an operator action, not a no_changes worker outcome")
	default:
		body := strings.TrimSpace(report.NoChangesRationale)
		if body == "" {
			body = "(rationale absent)"
		}
		return NoChangesOutcome{
			Satisfied:        false,
			Action:           NoChangesActionBadAttemptNoCooldown,
			CooldownEligible: false,
			EventKind:        NoChangesEventUnjustified,
			EventBody:        body,
			Label:            NoChangesLabelUnjustified,
		}
	}
}

func noChangesBlockedReasonIsInternal(reason, suggestedAction, rationale string) bool {
	text := strings.ToLower(strings.Join([]string{reason, suggestedAction, rationale}, "\n"))
	internalSignals := []string{
		"cannot be satisfied inside this bead",
		"inside this bead alone",
		"outside this bead",
		"outside the bead",
		"outside scope",
		"out of scope",
		"scope is too large",
		"too large",
		"needs split",
		"requires split",
		"requires decomposition",
		"requires a broad",
		"requires a broader",
		"broad signature migration",
		"broad caller migration",
		"broader api migration",
		"broader api",
		"repo-wide refactor",
		"follow_up_needed",
		"follow-up needed",

		"follow-up needed",
	}
	for _, signal := range internalSignals {
		if strings.Contains(text, signal) {
			return true
		}
	}
	return false
}

func noChangesUnsupportedStatusOutcome(status, reason string) NoChangesOutcome {
	body := fmt.Sprintf("status: %s rejected: %s", status, reason)
	return NoChangesOutcome{
		Satisfied:        false,
		Action:           NoChangesActionBadAttemptNoCooldown,
		CooldownEligible: false,
		EventKind:        NoChangesEventUnjustified,
		EventBody:        body,
		Reason:           body,
	}
}

func noChangesLifecycleEventBody(status, reason, suggestedAction string) string {
	body := "status=" + status
	if reason != "" {
		body += "\nreason=" + reason
	}
	if suggestedAction != "" {
		body += "\nsuggested_action=" + suggestedAction
	}
	return body
}

