	attempts := []escalation.PowerAttemptRecord{
		{PowerClass: string(escalation.PowerStandard), Status: ExecuteBeadStatusExecutionFailed, CostUSD: 0.10, DurationMS: 2000},
		{PowerClass: string(escalation.PowerSmart), Status: escalation.SuccessStatus, CostUSD: 0.50, DurationMS: 4000},
	}
	require.NoError(t,
		escalation.AppendEscalationSummaryEvent(
			store, target.ID, "test-worker", attempts, string(escalation.PowerSmart), time.Unix(1, 0).UTC()))

	events, err := store.Events(target.ID)
	require.NoError(t, err)
	var found *bead.BeadEvent
	for i := range events {
		if events[i].Kind == "escalation-summary" {
			found = &events[i]
			break
		}
	}
	require.NotNil(t, found, "escalation-summary event must be appended for the standard-default ladder run")
	assert.Contains(t, found.Summary, "winning_power_class=smart")
	assert.Contains(t, found.Summary, "attempts=2")
	assert.Contains(t, found.Body, `"power_class":"standard"`)
	assert.Contains(t, found.Body, `"power_class":"smart"`)
}

// nextPowerClass advances one rung up the cheap -> standard -> smart ladder.
// Mirrors the implicit ladder used by the work when escalating
// beyond a substantive failure. Smart is the top; further calls stay
// at smart (callers exhaust escalation when ShouldEscalate fires at smart).
func nextPowerClass(t escalation.PowerClass) escalation.PowerClass {
	switch t {
	case escalation.PowerCheap:
		return escalation.PowerStandard
	case escalation.PowerStandard:
		return escalation.PowerSmart
	default:
		return escalation.PowerSmart
	}
}

package escalation

import (
	"encoding/json"
	"fmt"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/bead"
)

// SuccessStatus mirrors agent.ExecuteBeadStatusSuccess. The agent package's
// TestEscalatableStatusesMatchAgentVocab guard catches drift if either side
// renames. Defined locally so escalation does not import agent.
const SuccessStatus = "success"

// EscalatableStatuses is the set of executor status strings that warrant
// retrying with a higher powerClass. Mirrors a subset of agent.ExecuteBeadStatus*
// strings; the agent package has a TestEscalatableStatusesMatchAgentVocab
// guard (see agent/tier_escalation_alignment_test.go) to catch drift.
var EscalatableStatuses = map[string]bool{
	"execution_failed":       true,
	"post_run_check_failed":  true,
	"land_conflict":          true,
	"review_request_changes": true,
	"review_block":           true,
}

// ShouldEscalate reports whether status warrants escalating to the next powerClass.
// Structural failures (e.g. validation errors) do not escalate because a
// smarter model cannot fix a malformed prompt or corrupted bead state.
func ShouldEscalate(status string) bool {
	return EscalatableStatuses[status]
}

// ProviderCooldownDuration is how long an unhealthy harness is skipped before
// re-probing. Five minutes gives most transient errors time to resolve without
// locking out a provider for too long.
//
// Per-harness cooldown tracking moved to the upstream agent service in v0.8.0:
// callers record failures via svc.RecordRouteAttempt and read cooldown state
// via svc.RouteStatus's RouteCandidateStatus.Healthy (ddx-7bc0c8d5).
const ProviderCooldownDuration = 5 * time.Minute

// FormatPowerAttemptBody formats the body of a power-attempt bead event.
func FormatPowerAttemptBody(powerClass, harness, model, probeResult, detail string) string {
	body := fmt.Sprintf("powerClass=%s harness=%s model=%s", powerClass, harness, model)
	if probeResult != "" {
		body += " probe=" + probeResult
	}
	if detail != "" {
		body += "\n" + detail
	}
	return body
}

// EscalationWinningExhausted is the sentinel value written into the
// winning_power_class field of an escalation-summary body when the escalation loop
// ran through every eligible powerClass without producing a successful attempt.
const EscalationWinningExhausted = "exhausted"

// PowerAttemptRecord is one row of an escalation trace. It captures the
// powerClass/harness/model that was tried, the status that attempt returned, and
// the cost/duration the harness reported for that attempt. Skipped powerClasses
// (no viable provider) are recorded with zero cost and zero duration.
type PowerAttemptRecord struct {
	PowerClass string  `json:"power_class"`
	Harness    string  `json:"harness,omitempty"`
	Model      string  `json:"model,omitempty"`
	Status     string  `json:"status"`
	CostUSD    float64 `json:"cost_usd"`
	DurationMS int64   `json:"duration_ms"`
}

// EscalationSummary is the structured body of a kind:escalation-summary bead
// event. It captures the entire escalation trace so an operator can diagnose
// which powerClasses were tried, which one won (if any), and how much the path cost.
type EscalationSummary struct {
	PowerAttempts     []PowerAttemptRecord `json:"power_attempts"`
	WinningPowerClass string               `json:"winning_power_class"`
	TotalCostUSD      float64              `json:"total_cost_usd"`
	WastedCostUSD     float64              `json:"wasted_cost_usd"`
}

// BuildEscalationSummary computes the summary body from the ordered list of
// attempts. winningPowerClass is the string of the powerClass whose attempt succeeded;
// pass "" when the escalation was exhausted, in which case winning_power_class is
// set to EscalationWinningExhausted. Total cost is the sum of all attempt
// costs; wasted cost is the sum of attempts whose status is not
// SuccessStatus.
func BuildEscalationSummary(attempts []PowerAttemptRecord, winningPowerClass string) EscalationSummary {
	out := EscalationSummary{
		PowerAttempts:     append([]PowerAttemptRecord{}, attempts...),
		WinningPowerClass: winningPowerClass,
	}
	if out.WinningPowerClass == "" {
		out.WinningPowerClass = EscalationWinningExhausted
	}
	for _, a := range attempts {
		out.TotalCostUSD += a.CostUSD
		if a.Status != SuccessStatus {
			out.WastedCostUSD += a.CostUSD
		}
	}
	return out
}

// BeadEventAppender records append-only evidence events on a bead. Mirrors
// agent.BeadEventAppender so escalation can append events without importing
// agent. *bead.Store satisfies both interfaces.
type BeadEventAppender interface {
	AppendEvent(id string, event bead.BeadEvent) error
}

// AppendEscalationSummaryEvent writes a kind:escalation-summary event to the
// bead with a JSON body describing the powerClass escalation trace. It is a
// best-effort operation — errors from the underlying store are returned so
// callers can log them, but callers typically ignore the error so telemetry
// failures never abort the main execute-bead flow.
func AppendEscalationSummaryEvent(appender BeadEventAppender, beadID, actor string, attempts []PowerAttemptRecord, winningPowerClass string, createdAt time.Time) error {
	if appender == nil || beadID == "" {
		return nil
	}
	summary := BuildEscalationSummary(attempts, winningPowerClass)
	body, err := json.Marshal(summary)
	if err != nil {
		return err
	}
	return appender.AppendEvent(beadID, bead.BeadEvent{
		Kind:      "escalation-summary",
		Summary:   fmt.Sprintf("winning_power_class=%s attempts=%d total_cost_usd=%.4f wasted_cost_usd=%.4f", summary.WinningPowerClass, len(attempts), summary.TotalCostUSD, summary.WastedCostUSD),
		Body:      string(body),
		Actor:     actor,
		Source:    "legacy agent work",
		CreatedAt: createdAt,
	})
}

package executeloop

import (
	"strings"

	"github.com/DocumentDrivenDX/ddx/internal/escalation"
)

// TryLoopState names the in-memory states used while ddx try/work evaluates a
// single bead attempt. Persisted bead lifecycle remains the six statuses owned
// by TD-027; these states are control-flow states only.
type TryLoopState string

const (
	TryLoopStateClassifyResult TryLoopState = "classify_result"
	TryLoopStateRetryPower     TryLoopState = "retry_power"
	TryLoopStateStopAttempt    TryLoopState = "stop_attempt"
)

// TryLoopAction is the action selected by the attempt state machine.
type TryLoopAction string

const (
	TryLoopActionStop       TryLoopAction = "stop"
	TryLoopActionRetryPower TryLoopAction = "retry_power"
)

// FloorFinder returns the next viable MinPower floor above the supplied power.
type FloorFinder interface {
	Next(actualPower int) (int, error)
}

// AttemptTransitionInput is the complete input the try-loop state machine needs
// to decide whether another implementation attempt is useful.
type AttemptTransitionInput struct {
	Status          string
	Detail          string
	CurrentMinPower int
	ActualPower     int

	Disrupted                bool
	BudgetExhausted          bool
	AllowInfrastructureRetry bool
}

// AttemptTransition is the state-machine decision for one completed attempt.
type AttemptTransition struct {
	State        TryLoopState
	Action       TryLoopAction
	NextMinPower int
	Reason       string
}

// DecideAttemptTransition implements the ddx try retry state machine for one
// attempt result. The default bias is forward progress: semantic failures move
// up the model-power ladder, while retryable provider-connectivity failures can
// be retried immediately with MinPower set just above the failed route's actual
// power. Infrastructure failures without concrete route evidence still stop the
// current attempt; a smarter model cannot fix an absent service with no
// alternate power signal.
func DecideAttemptTransition(input AttemptTransitionInput, ladder FloorFinder) AttemptTransition {
	if input.Disrupted {
		return stopTransition("disrupted")
	}
	if input.BudgetExhausted {
		return stopTransition("budget_exhausted")
	}
	if !escalation.ShouldEscalate(input.Status) {
		return stopTransition("terminal_status")
	}

	if escalation.IsInfrastructureFailure(input.Status, input.Detail) {
		if !input.AllowInfrastructureRetry || input.ActualPower <= 0 || !isProviderConnectivityDetail(input.Detail) {
			return stopTransition("infrastructure_no_retry_route")
		}
		next := input.ActualPower + 1
		if next <= input.CurrentMinPower {
			next = input.CurrentMinPower + 1
		}
		return AttemptTransition{
			State:        TryLoopStateRetryPower,
			Action:       TryLoopActionRetryPower,
			NextMinPower: next,
			Reason:       "infrastructure_retry_with_higher_min_power",
		}
	}

	basis := input.CurrentMinPower
	if input.ActualPower > 0 {
		basis = input.ActualPower
	}
	next, err := nextLadderFloor(ladder, basis)
	if err != nil {
		return stopTransition("power_ladder_exhausted")
	}
	return AttemptTransition{
		State:        TryLoopStateRetryPower,
		Action:       TryLoopActionRetryPower,
		NextMinPower: next,
		Reason:       "semantic_retry_with_higher_min_power",
	}
}

func stopTransition(reason string) AttemptTransition {
	return AttemptTransition{
		State:  TryLoopStateStopAttempt,
		Action: TryLoopActionStop,
		Reason: reason,
	}
}

func nextLadderFloor(ladder FloorFinder, basis int) (int, error) {
	if ladder == nil {
		return 0, errNoFloorFinder{}
	}
	return ladder.Next(basis)
}

type errNoFloorFinder struct{}

func (errNoFloorFinder) Error() string { return "no floor finder configured" }

func isProviderConnectivityDetail(detail string) bool {
	lower := strings.ToLower(detail)
	for _, marker := range []string{"provider_connectivity", "connection refused", "no route to host", "network is unreachable", "i/o timeout", "connection reset", "dial tcp"} {
		if strings.Contains(lower, marker) {
			return true
		}
	}
	return false
}

