	assert.Equal(t, 0, noChangesMinPowerOverride(unjustifiedUpdated, 70))
	_, hasHint := unjustifiedUpdated.Extra[executeLoopNoChangesNextMinPowerKey]
	assert.False(t, hasHint, "non-semantic no_changes must not persist a next-min-power hint")

	connectivityStore := bead.NewStore(t.TempDir())
	require.NoError(t, connectivityStore.Init(context.Background()))
	require.NoError(t, connectivityStore.Create(context.Background(), &bead.Bead{ID: "ddx-bead-route", Title: "provider connectivity retry"}))
	var floorCalls int
	require.NoError(t, applyProviderConnectivityRouteExclusion(connectivityStore, "ddx-bead-route", "worker", ExecuteBeadReport{
		Provider:    "grendel",
		Model:       "mistral-7b",
		ActualPower: 15,
		Status:      ExecuteBeadStatusExecutionFailed,
	}, false, func(actualPower int) (int, error) {
		floorCalls++
		return actualPower + 1, nil
	}, time.Now().UTC()))
	assert.Zero(t, floorCalls, "provider connectivity retries must not consult the min-power ladder")

	smartStore := bead.NewStore(t.TempDir())
	require.NoError(t, smartStore.Init(context.Background()))
	require.NoError(t, smartStore.Create(context.Background(), &bead.Bead{ID: "ddx-bead-smart", Title: "smart retry should stay at same tier"}))
	require.NoError(t, applyNoChangesSmartRetry(smartStore, "ddx-bead-smart", "worker", &agenttry.NoChangesOutcome{
		Action:          agenttry.NoChangesActionKeepOpenSmartRetry,
		EventKind:       agenttry.NoChangesEventAutonomousRetry,
		Reason:          "autonomous work remains possible",
		SuggestedAction: "retry with a smart agent",
	}, 40, func(actualPower int) (int, error) {
		t.Fatalf("smart retry must not consult nextFloorFn")
		return 0, nil
	}))
	smartUpdated, err := smartStore.Get(context.Background(), "ddx-bead-smart")
	require.NoError(t, err)
	assert.Equal(t, bead.StatusOpen, smartUpdated.Status)
	assert.Equal(t, 0, noChangesMinPowerOverride(smartUpdated, 40))
	_, hasHint = smartUpdated.Extra[executeLoopNoChangesNextMinPowerKey]
	assert.False(t, hasHint, "smart retry must not persist a next-min-power hint")
}

func TestNoEvidenceProduced_DoesNotEscalateMinPower(t *testing.T) {
	out, err := noChangesAttempt(t, "")
	require.NoError(t, err)
	require.NotNil(t, out.NoChanges)
	assert.Equal(t, 1, out.Report.EscalationCount, "IncrNoChangesCount must increment on the first no-evidence attempt")
	assert.Equal(t, agenttry.NoChangesActionBadAttemptNoCooldown, out.NoChanges.Action)

	store := bead.NewStore(t.TempDir())
	require.NoError(t, store.Init(context.Background()))
	require.NoError(t, store.Create(context.Background(), &bead.Bead{ID: "ddx-bead-2", Title: "no-evidence escalation"}))

	require.NoError(t, applyNoChangesBadAttemptEscalation(store, "ddx-bead-2", "worker", out.NoChanges, out.Report.ActualPower, func(actualPower int) (int, error) {
		t.Fatalf("unjustified no_changes must not consult nextFloorFn")
		return 0, nil
	}))

	updated, err := store.Get(context.Background(), "ddx-bead-2")
	require.NoError(t, err)
	require.Equal(t, bead.StatusOpen, updated.Status)
	assert.Equal(t, 0, noChangesMinPowerOverride(updated, 70))
	_, hasHint := updated.Extra[executeLoopNoChangesNextMinPowerKey]
	assert.False(t, hasHint, "no-evidence no_changes must not persist a next-min-power hint")
}

func TestNoChangesEscalation_BoundedByLadderCap(t *testing.T) {
	store := bead.NewStore(t.TempDir())
	require.NoError(t, store.Init(context.Background()))
	require.NoError(t, store.Create(context.Background(), &bead.Bead{ID: "ddx-bead-3", Title: "ladder cap escalation"}))

	noChanges := &agenttry.NoChangesOutcome{
		Action:          agenttry.NoChangesActionBadAttemptNoCooldown,
		EventKind:       agenttry.NoChangesEventUnverified,
		Reason:          "stronger model needed but no higher rung remains",
		SuggestedAction: "park for operator review",
	}

	require.NoError(t, applyNoChangesBadAttemptEscalation(store, "ddx-bead-3", "worker", noChanges, 90, func(int) (int, error) {
		return 0, fmt.Errorf("ladder exhausted")
	}))

	updated, err := store.Get(context.Background(), "ddx-bead-3")
	require.NoError(t, err)
	require.Equal(t, bead.StatusProposed, updated.Status)
	assert.Empty(t, updated.Owner)
	_, hasHint := updated.Extra[executeLoopNoChangesNextMinPowerKey]
	assert.False(t, hasHint, "top-of-ladder parking must clear the next-min-power hint")
}

